import{_ as e,o as s,a as i,ag as t}from"./chunks/framework.C2qfZH9T.js";const u=JSON.parse('{"title":"Common Pitfalls","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/common-pitfalls.md","filePath":"advanced/common-pitfalls.md","lastUpdated":1774275271000}'),n={name:"advanced/common-pitfalls.md"};function o(l,a,r,h,d,c){return s(),i("div",null,a[0]||(a[0]=[t(`<h1 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h1><p>This page documents frequent issues encountered by developers working with Bagisto, along with solutions derived from the actual codebase.</p><h2 id="installation-setup" tabindex="-1">Installation &amp; Setup <a class="header-anchor" href="#installation-setup" aria-label="Permalink to &quot;Installation &amp; Setup&quot;">​</a></h2><h3 id="php-version-mismatch" tabindex="-1">PHP Version Mismatch <a class="header-anchor" href="#php-version-mismatch" aria-label="Permalink to &quot;PHP Version Mismatch&quot;">​</a></h3><p>Bagisto requires <strong>PHP 8.3 or higher</strong>. The <code>composer.json</code> specifies <code>&quot;php&quot;: &quot;^8.3&quot;</code>. Running on PHP 8.2 or lower will cause dependency resolution failures.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Verify your PHP version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><h3 id="missing-php-extensions" tabindex="-1">Missing PHP Extensions <a class="header-anchor" href="#missing-php-extensions" aria-label="Permalink to &quot;Missing PHP Extensions&quot;">​</a></h3><p>The following extensions are required (from <code>composer.json</code>):</p><ul><li><code>ext-calendar</code></li><li><code>ext-curl</code></li><li><code>ext-intl</code></li><li><code>ext-mbstring</code></li><li><code>ext-openssl</code></li><li><code>ext-pdo</code></li><li><code>ext-pdo_mysql</code></li><li><code>ext-tokenizer</code></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check installed extensions</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;calendar|curl|intl|mbstring|openssl|pdo|tokenizer&quot;</span></span></code></pre></div><h3 id="storage-link-not-created" tabindex="-1">Storage Link Not Created <a class="header-anchor" href="#storage-link-not-created" aria-label="Permalink to &quot;Storage Link Not Created&quot;">​</a></h3><p>Product images and uploads won&#39;t display without the storage symlink:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> storage:link</span></span></code></pre></div><p>This creates <code>public/storage</code> → <code>storage/app/public</code>. If images still don&#39;t load, verify <code>APP_URL</code> in <code>.env</code> matches your actual domain/port.</p><h3 id="app-url-mismatch" tabindex="-1">APP_URL Mismatch <a class="header-anchor" href="#app-url-mismatch" aria-label="Permalink to &quot;APP_URL Mismatch&quot;">​</a></h3><p>A mismatch between <code>APP_URL</code> and your actual URL causes broken assets, images, and redirects. This is especially common when switching between local development and production.</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Must match exactly, including port</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">APP_URL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=http://localhost:8000</span></span></code></pre></div><h2 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h2><h3 id="mysql-version" tabindex="-1">MySQL Version <a class="header-anchor" href="#mysql-version" aria-label="Permalink to &quot;MySQL Version&quot;">​</a></h3><p>Bagisto requires MySQL 8.0.32 or higher. The <code>utf8mb4_unicode_ci</code> collation is recommended for full Unicode support.</p><h3 id="migration-order-matters" tabindex="-1">Migration Order Matters <a class="header-anchor" href="#migration-order-matters" aria-label="Permalink to &quot;Migration Order Matters&quot;">​</a></h3><p>When running <code>php artisan migrate:fresh --seed</code>, Bagisto&#39;s package migrations run in the order they&#39;re discovered by Concord. If you add a custom package with foreign key dependencies on core tables, ensure your migrations have timestamps that come after the core migrations.</p><h3 id="database-session-driver" tabindex="-1">Database Session Driver <a class="header-anchor" href="#database-session-driver" aria-label="Permalink to &quot;Database Session Driver&quot;">​</a></h3><p>Bagisto defaults to <code>SESSION_DRIVER=database</code>. If you run <code>php artisan migrate:fresh</code> but forget <code>--seed</code>, the sessions table exists but the application may behave unexpectedly without seed data.</p><h2 id="package-development" tabindex="-1">Package Development <a class="header-anchor" href="#package-development" aria-label="Permalink to &quot;Package Development&quot;">​</a></h2><h3 id="service-provider-registration" tabindex="-1">Service Provider Registration <a class="header-anchor" href="#service-provider-registration" aria-label="Permalink to &quot;Service Provider Registration&quot;">​</a></h3><p>Every Bagisto package needs a service provider registered in the root <code>composer.json</code> autoload section. Forgetting this step means your package won&#39;t be discovered:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;autoload&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;psr-4&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;Webkul\\\\YourPackage\\\\&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;packages/Webkul/YourPackage/src&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>After adding, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">composer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dump-autoload</span></span></code></pre></div><h3 id="concord-module-registration" tabindex="-1">Concord Module Registration <a class="header-anchor" href="#concord-module-registration" aria-label="Permalink to &quot;Concord Module Registration&quot;">​</a></h3><p>Packages must extend <code>Webkul\\Core\\Providers\\CoreModuleServiceProvider</code> (or register as a Concord module) to be properly recognized. Check that your service provider is registered in <code>config/concord.php</code> or uses Laravel&#39;s package discovery.</p><h3 id="bypassing-the-repository-pattern" tabindex="-1">Bypassing the Repository Pattern <a class="header-anchor" href="#bypassing-the-repository-pattern" aria-label="Permalink to &quot;Bypassing the Repository Pattern&quot;">​</a></h3><p>Bagisto&#39;s repository cache automatically invalidates when you use repositories for CRUD. If you bypass the repository and write raw Eloquent queries, cached data can become stale. Always prefer repository methods:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ✅ Correct — uses repository, triggers cache invalidation</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$this</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">productRepository</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($data, $id);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ❌ Avoid — bypasses cache invalidation</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Product</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;id&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, $id)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">($data);</span></span></code></pre></div><h2 id="frontend-assets" tabindex="-1">Frontend &amp; Assets <a class="header-anchor" href="#frontend-assets" aria-label="Permalink to &quot;Frontend &amp; Assets&quot;">​</a></h2><h3 id="vite-build-required" tabindex="-1">Vite Build Required <a class="header-anchor" href="#vite-build-required" aria-label="Permalink to &quot;Vite Build Required&quot;">​</a></h3><p>After changing CSS or JavaScript in a package, you must rebuild assets:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Development (with hot reload)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Production build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Each package with frontend assets (Admin, Shop) has its own <code>vite.config.js</code>. The root <code>vite.config.js</code> handles the main application assets.</p><h3 id="tailwind-css-purging" tabindex="-1">Tailwind CSS Purging <a class="header-anchor" href="#tailwind-css-purging" aria-label="Permalink to &quot;Tailwind CSS Purging&quot;">​</a></h3><p>If custom Tailwind classes don&#39;t appear in production, ensure your Blade file paths are included in the relevant <code>tailwind.config.js</code> content array. Tailwind only includes classes that appear in scanned files.</p><h2 id="caching-issues" tabindex="-1">Caching Issues <a class="header-anchor" href="#caching-issues" aria-label="Permalink to &quot;Caching Issues&quot;">​</a></h2><h3 id="stale-configuration-after-env-changes" tabindex="-1">Stale Configuration After <code>.env</code> Changes <a class="header-anchor" href="#stale-configuration-after-env-changes" aria-label="Permalink to &quot;Stale Configuration After \`.env\` Changes&quot;">​</a></h3><p>After modifying <code>.env</code>, always clear the config cache:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config:clear</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or clear everything</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> optimize:clear</span></span></code></pre></div><p>If you&#39;ve run <code>php artisan config:cache</code>, the cached config takes precedence over <code>.env</code> values until cleared.</p><h3 id="response-cache-serving-old-pages" tabindex="-1">Response Cache Serving Old Pages <a class="header-anchor" href="#response-cache-serving-old-pages" aria-label="Permalink to &quot;Response Cache Serving Old Pages&quot;">​</a></h3><p>If storefront pages show stale content after product/category changes, the FPC event listeners may not be covering your change. Check that <code>RESPONSE_CACHE_ENABLED=true</code> and clear manually if needed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> responsecache:clear</span></span></code></pre></div><h2 id="queue-jobs" tabindex="-1">Queue &amp; Jobs <a class="header-anchor" href="#queue-jobs" aria-label="Permalink to &quot;Queue &amp; Jobs&quot;">​</a></h2><h3 id="sync-queue-in-production" tabindex="-1">Sync Queue in Production <a class="header-anchor" href="#sync-queue-in-production" aria-label="Permalink to &quot;Sync Queue in Production&quot;">​</a></h3><p>The default <code>QUEUE_CONNECTION=sync</code> processes all jobs synchronously during the HTTP request. This works for development but causes timeouts in production when saving products with Elasticsearch indexing or processing large imports.</p><p>Switch to <code>redis</code> or <code>database</code> driver for production and run a queue worker:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">QUEUE_CONNECTION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=redis</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> queue:work</span></span></code></pre></div><h2 id="mail-configuration" tabindex="-1">Mail Configuration <a class="header-anchor" href="#mail-configuration" aria-label="Permalink to &quot;Mail Configuration&quot;">​</a></h2><h3 id="dynamic-smtp" tabindex="-1">Dynamic SMTP <a class="header-anchor" href="#dynamic-smtp" aria-label="Permalink to &quot;Dynamic SMTP&quot;">​</a></h3><p>Bagisto uses a custom <code>bagisto-dynamic-smtp</code> mail driver that reads SMTP settings from the database (admin panel configuration) rather than <code>.env</code> only. If email settings in the admin panel differ from <code>.env</code>, the admin panel values take precedence.</p><p>This is handled by <code>Webkul\\Core\\Providers\\DynamicSmtpServiceProvider</code>.</p><h2 id="admin-panel" tabindex="-1">Admin Panel <a class="header-anchor" href="#admin-panel" aria-label="Permalink to &quot;Admin Panel&quot;">​</a></h2><h3 id="custom-admin-url" tabindex="-1">Custom Admin URL <a class="header-anchor" href="#custom-admin-url" aria-label="Permalink to &quot;Custom Admin URL&quot;">​</a></h3><p>The admin panel URL is configured via <code>APP_ADMIN_URL</code> in <code>.env</code>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">APP_ADMIN_URL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=admin</span></span></code></pre></div><p>Changing this value requires clearing the route cache:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> route:clear</span></span></code></pre></div><h3 id="acl-not-working" tabindex="-1">ACL Not Working <a class="header-anchor" href="#acl-not-working" aria-label="Permalink to &quot;ACL Not Working&quot;">​</a></h3><p>If a custom admin menu item doesn&#39;t respect ACL, verify that:</p><ol><li>Your <code>Config/acl.php</code> file defines the permission key</li><li>Your route or controller checks the permission with the correct key</li><li>The admin role has the permission enabled</li></ol><h2 id="elasticsearch" tabindex="-1">Elasticsearch <a class="header-anchor" href="#elasticsearch" aria-label="Permalink to &quot;Elasticsearch&quot;">​</a></h2><h3 id="connection-refused" tabindex="-1">Connection Refused <a class="header-anchor" href="#connection-refused" aria-label="Permalink to &quot;Connection Refused&quot;">​</a></h3><p>If product search fails with Elasticsearch errors, verify:</p><ol><li>Elasticsearch is running and accessible</li><li>The <code>.env</code> or <code>config/elasticsearch.php</code> has the correct host URL</li><li>Elasticsearch version is 7.x or 8.x compatible</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Test Elasticsearch connection</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:9200</span></span></code></pre></div><h3 id="index-out-of-sync" tabindex="-1">Index Out of Sync <a class="header-anchor" href="#index-out-of-sync" aria-label="Permalink to &quot;Index Out of Sync&quot;">​</a></h3><p>After bulk changes, reindex Elasticsearch:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> indexer:index</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type=elastic</span></span></code></pre></div><h2 id="multi-channel-multi-locale" tabindex="-1">Multi-Channel / Multi-Locale <a class="header-anchor" href="#multi-channel-multi-locale" aria-label="Permalink to &quot;Multi-Channel / Multi-Locale&quot;">​</a></h2><h3 id="channel-specific-configuration" tabindex="-1">Channel-Specific Configuration <a class="header-anchor" href="#channel-specific-configuration" aria-label="Permalink to &quot;Channel-Specific Configuration&quot;">​</a></h3><p>Many configuration values in Bagisto are channel-specific and locale-specific. When reading config with <code>core()-&gt;getConfigData()</code>, the current channel and locale context matters. A setting that works on one channel may return <code>null</code> on another if not configured.</p><h3 id="maintenance-mode-is-per-channel" tabindex="-1">Maintenance Mode is Per-Channel <a class="header-anchor" href="#maintenance-mode-is-per-channel" aria-label="Permalink to &quot;Maintenance Mode is Per-Channel&quot;">​</a></h3><p>Bagisto&#39;s <code>php artisan down</code> command sets maintenance mode on all channels. If you only want to take down one channel, manage the <code>is_maintenance_on</code> flag directly on the channel record rather than using the artisan command.</p>`,82)]))}const k=e(n,[["render",o]]);export{u as __pageData,k as default};
